(function(global){
  const R = { Fragment: Symbol('Fragment') };
  let states = [], cursor = 0, rerender = null;
  R.createElement = function(type, props){
    const children = Array.prototype.slice.call(arguments, 2).flat(Infinity).filter(x => x !== false && x !== true && x != null);
    props = props || {};
    if (children.length) props.children = children.length === 1 ? children[0] : children;
    return { type, props, children };
  };
  R.useState = function(initial){
    const id = cursor++;
    if (states[id] === undefined) states[id] = typeof initial === 'function' ? initial() : initial;
    const set = value => { states[id] = typeof value === 'function' ? value(states[id]) : value; rerender && rerender(); };
    return [states[id], set];
  };
  R.useMemo = function(fn){ return fn(); };
  function setStyle(el, style){ if(!style) return; Object.keys(style).forEach(k => el.style[k] = style[k]); }
  function setProp(el, k, v){
    if (k === 'children' || v == null || v === false) return;
    if (k === 'className') el.setAttribute('class', v);
    else if (k === 'style') setStyle(el, v);
    else if (k.startsWith('on') && typeof v === 'function') el.addEventListener(k.slice(2).toLowerCase(), v);
    else if (k === 'defaultValue') el.value = v;
    else if (k === 'value') el.value = v;
    else el.setAttribute(k, v === true ? '' : String(v));
  }
  function renderNode(node){
    if (node == null || node === false || node === true) return document.createTextNode('');
    if (Array.isArray(node)) { const f=document.createDocumentFragment(); node.forEach(n=>f.appendChild(renderNode(n))); return f; }
    if (typeof node === 'string' || typeof node === 'number') return document.createTextNode(String(node));
    if (typeof node.type === 'function') return renderNode(node.type(node.props || {}));
    if (node.type === R.Fragment) return renderNode(node.props && node.props.children ? node.props.children : node.children);
    const el = document.createElement(node.type);
    Object.keys(node.props || {}).forEach(k => setProp(el, k, node.props[k]));
    const children = node.props && node.props.children !== undefined ? node.props.children : node.children;
    (Array.isArray(children) ? children : [children]).filter(x=>x!=null).forEach(c => el.appendChild(renderNode(c)));
    return el;
  }
  global.__tinyReactRender = function(root, element){ cursor = 0; root.replaceChildren(renderNode(element)); };
  global.__tinyReactSetRerender = fn => rerender = fn;
  global.React = R;
})(window);
